class InAppPurchaseManager(
    private val context: Context,
    private val secureStorage: SecureStorageManager
) {
    private var billingClient: BillingClient? = null
    private val purchaseUpdateListener = PurchasesUpdatedListener { billingResult, purchases ->
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            for (purchase in purchases) {
                handlePurchase(purchase)
            }
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            onPurchaseResult(PaymentResult.Cancelled)
        } else {
            onPurchaseResult(PaymentResult.Error("Purchase failed: ${billingResult.debugMessage}"))
        }
    }

    private var onPurchaseResult: (PaymentResult) -> Unit = {}

    fun initialize(onResult: (Boolean) -> Unit) {
        billingClient = BillingClient.newBuilder(context)
            .setListener(purchaseUpdateListener)
            .enablePendingPurchases()
            .build()

        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    onResult(true)
                } else {
                    onResult(false)
                }
            }

            override fun onBillingServiceDisconnected() {
                initialize(onResult)
            }
        })
    }

    suspend fun queryProducts(productIds: List<String>): List<InAppProduct> {
        return withContext(Dispatchers.IO) {
            val products = mutableListOf<InAppProduct>()

            val productParams = QueryProductDetailsParams.newBuilder()
                .setProductList(
                    productIds.map { productId ->
                        QueryProductDetailsParams.Product.newBuilder()
                            .setProductId(productId)
                            .setProductType(BillingClient.ProductType.INAPP)
                            .build()
                    }
                )
                .build()

            val productDetailsResult = billingClient?.queryProductDetails(productParams)
            productDetailsResult?.productDetailsList?.forEach { productDetails ->
                productDetails.oneTimePurchaseOfferDetails?.let { offer ->
                    products.add(
                        InAppProduct(
                            productId = productDetails.productId,
                            name = productDetails.name,
                            description = productDetails.description,
                            price = offer.formattedPrice,
                            priceMicros = offer.priceAmountMicros,
                            currency = offer.priceCurrencyCode,
                            type = ProductType.CONSUMABLE
                        )
                    )
                }
            }

            products
        }
    }

    fun purchaseProduct(
        activity: Activity,
        productId: String,
        onResult: (PaymentResult) -> Unit
    ) {
        this.onPurchaseResult = onResult

        CoroutineScope(Dispatchers.IO).launch {
            val productParams = QueryProductDetailsParams.newBuilder()
                .setProductList(
                    listOf(
                        QueryProductDetailsParams.Product.newBuilder()
                            .setProductId(productId)
                            .setProductType(BillingClient.ProductType.INAPP)
                            .build()
                    )
                )
                .build()

            val productDetailsResult = billingClient?.queryProductDetails(productParams)
            val productDetails = productDetailsResult?.productDetailsList?.firstOrNull()

            if (productDetails != null) {
                withContext(Dispatchers.Main) {
                    val productDetailsParamsList = listOf(
                        BillingFlowParams.ProductDetailsParams.newBuilder()
                            .setProductDetails(productDetails)
                            .build()
                    )

                    val billingFlowParams = BillingFlowParams.newBuilder()
                        .setProductDetailsParamsList(productDetailsParamsList)
                        .build()

                    billingClient?.launchBillingFlow(activity, billingFlowParams)
                }
            } else {
                onResult(PaymentResult.Error("Product not found"))
            }
        }
    }

    private fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!purchase.isAcknowledged) {
                acknowledgePurchase(purchase)
            }

            val transaction = Transaction(
                id = purchase.orderId ?: UUID.randomUUID().toString(),
                amount = 0.0,
                currency = "USD",
                status = TransactionStatus.COMPLETED,
                timestamp = purchase.purchaseTime,
                description = "In-app purchase",
                paymentMethodId = "google_play"
            )

            secureStorage.saveSecureData(
                "purchase_${purchase.orderId}",
                Gson().toJson(purchase)
            )

            onPurchaseResult(PaymentResult.Success(transaction))
        }
    }

    private fun acknowledgePurchase(purchase: Purchase) {
        val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        billingClient?.acknowledgePurchase(acknowledgePurchaseParams) { billingResult ->
            if (billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
                Log.e("InAppPurchase", "Failed to acknowledge purchase: ${billingResult.debugMessage}")
            }
        }
    }

    fun consumePurchase(purchaseToken: String, onResult: (Boolean) -> Unit) {
        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        billingClient?.consumeAsync(consumeParams) { billingResult, _ ->
            onResult(billingResult.responseCode == BillingClient.BillingResponseCode.OK)
        }
    }

    fun disconnect() {
        billingClient?.endConnection()
    }
}

